#include <bits/stdc++.h>
using namespace std;

int a[100005], b[100005];

int main()
{
    int t;
    cin >> t;
    while(t--)
    {
        int n, m, ans = 0;
        cin >> n >> m;
        for(int i = 1; i <= n; i++)
            cin >> a[i];
        for(int i = 1; i <= m; i++)
            cin >> b[i];
        sort(a + 1, a + n + 1);
        sort(b + 1, b + m + 1);
        b[0] = 0;b[m + 1] = 2e9;
        for(int i = 0; i <= m + 1; i++)
        {
            int t1 = upper_bound(a + 1, a + n + 1, b[i]) - a;
            int t2 = lower_bound(a + 1, a + n + 1, b[i + 1]) - a;
            ans = max(ans, t2 - t1);
        }
        cout << (ans == 0?"Impossible":to_string(ans)) << endl;
    }
}
